let allVideos = [];

// Collect videos from all inputs
for (const item of items) {
  const videos = item.json?.data?.videos;

  if (!videos) continue;

  // If it's already an array
  if (Array.isArray(videos)) {
    allVideos = allVideos.concat(videos);
  } 
  // If it's an object (0,1,2 keys)
  else if (typeof videos === "object") {
    allVideos = allVideos.concat(Object.values(videos));
  }
}

// Recency score
function getRecencyScore(video) {
  if (video.publishedAt) {
    return new Date(video.publishedAt).getTime();
  }
  return 0;
}

// Engagement score
function getEngagement(video) {
  const views = video.viewCountInt || 0;

  if (!video.publishedAt) return views;

  const ageDays =
    (Date.now() - new Date(video.publishedAt).getTime()) /
    (1000 * 60 * 60 * 24);

  return views / Math.max(ageDays, 1);
}

// Sort by Views
const byViews = [...allVideos].sort(
  (a, b) => (b.viewCountInt || 0) - (a.viewCountInt || 0)
);

// Sort by Recency
const byRecency = [...allVideos].sort(
  (a, b) => getRecencyScore(b) - getRecencyScore(a)
);

// Sort by Engagement
const byEngagement = [...allVideos].sort(
  (a, b) => getEngagement(b) - getEngagement(a)
);


// --- NEW: Format arrays into clean text for the AI Agent ---
const formatForAI = (videos) => {
  // Slicing to 30 to match your node's intent and save AI tokens
  return videos.slice(0, 30).map((v, index) => {
    // Using the keys visible in your previous screenshot
    return `${index + 1}. Title: ${v.title || 'Unknown'}
   Views: ${v.viewCountText || 'N/A'}
   URL: ${v.url || 'No URL'}`;
  }).join('\n\n'); 
};


return [
  {
    json: {
      // Keeping your original arrays intact
      sortedByViews: byViews,
      sortedByRecency: byRecency,
      sortedByEngagement: byEngagement,

      // Adding the formatted strings for your AI prompt
      aiTextViews: formatForAI(byViews),
      aiTextRecency: formatForAI(byRecency),
      aiTextEngagement: formatForAI(byEngagement)
    }
  }
];

