let allVideos = [];

// 1. Extract videos from the specific TikTok JSON structure
for (const item of items) {
  // Navigate to the search_item_list in your provided file
  const searchList = item.json?.data?.search_item_list;

  if (!searchList) continue;

  // TikTok results usually come as an object with string keys ("0", "1", "2")
  const videoEntries = Object.values(searchList);

  for (const entry of videoEntries) {
    const v = entry.aweme_info;
    if (!v) continue;

    // Standardize the data for easier sorting
    allVideos.push({
      title: v.desc || 'No Description',
      url: v.url || `https://www.tiktok.com/video/${v.aweme_id}`,
      viewCountInt: v.statistics?.play_count || 0,
      publishedAt: v.create_time * 1000, // TikTok uses Unix seconds, JS needs milliseconds
      // Engagement: Likes + Comments + Shares + Saves
      totalInteractions: (v.statistics?.digg_count || 0) + 
                         (v.statistics?.comment_count || 0) + 
                         (v.statistics?.share_count || 0) + 
                         (v.statistics?.collect_count || 0)
    });
  }
}

// 2. Helper: Recency Score
function getRecencyScore(video) {
  return video.publishedAt || 0;
}

// 3. Helper: Engagement Score (Interactions relative to video age)
function getEngagementScore(video) {
  if (!video.publishedAt) return video.totalInteractions;

  const ageDays = (Date.now() - video.publishedAt) / (1000 * 60 * 60 * 24);
  // Velocity: average interactions per day (min 1 day to avoid division by zero)
  return video.totalInteractions / Math.max(ageDays, 1);
}

// --- SORTING ---

// Sort by Views
const byViews = [...allVideos].sort((a, b) => b.viewCountInt - a.viewCountInt);

// Sort by Recency (Newest first)
const byRecency = [...allVideos].sort((a, b) => getRecencyScore(b) - getRecencyScore(a));

// Sort by Engagement (Highest velocity first)
const byEngagement = [...allVideos].sort((a, b) => getEngagementScore(b) - getEngagementScore(a));


// --- FORMATTING FOR AI AGENT ---
const formatForAI = (videos, type) => {
  return `TOP 30 VIDEOS BY ${type.toUpperCase()}:\n` + 
    videos.slice(0, 30).map((v, index) => {
      const date = new Date(v.publishedAt).toLocaleDateString();
      return `${index + 1}. Title: ${v.title}
   Views: ${v.viewCountInt.toLocaleString()}
   Date: ${date}
   URL: ${v.url}`;
    }).join('\n\n'); 
};


// --- RETURN TO n8n ---
return [
  {
    json: {
      // Raw data arrays
      sortedByViews: byViews.slice(0, 30),
      sortedByRecency: byRecency.slice(0, 30),
      sortedByEngagement: byEngagement.slice(0, 30),

      // Formatted text for AI prompts
      aiTextViews: formatForAI(byViews, 'Views'),
      aiTextRecency: formatForAI(byRecency, 'Recency'),
      aiTextEngagement: formatForAI(byEngagement, 'Engagement')
    }
  }
];

const data = $input.first().json.output;

// convert object to readable text
const text = JSON.stringify(data, null, 2);

return [
  {
    json: {
      ai_text: text
    }
  }
];

